import{_ as e,o as i,c as o,a0 as r}from"./chunks/framework.BjpW4enL.js";const m=JSON.parse('{"title":"NEXUS Canonical Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/CANONICAL_ARCHITECTURE.md","filePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/CANONICAL_ARCHITECTURE.md","lastUpdated":1782593311000}'),t={name:"Z_Archive/wiki_legacy/archive/legacy_pre_federation/CANONICAL_ARCHITECTURE.md"};function l(n,a,d,s,c,u){return i(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="nexus-canonical-architecture" tabindex="-1">NEXUS Canonical Architecture <a class="header-anchor" href="#nexus-canonical-architecture" aria-label="Permalink to &quot;NEXUS Canonical Architecture&quot;">​</a></h1><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>Este documento é a síntese arquitetural canônica do NEXUS. Ele existe para reduzir a distância entre:</p><ul><li>visão original,</li><li>runtime atual,</li><li>e direção de refactor.</li></ul><p>Quando houver conflito entre documentos panorâmicos, este arquivo deve servir como ponto de reconciliação de alto nível. Ele define papéis de camadas e invariantes, não o contrato detalhado do runtime.</p><h2 id="estrutura-do-sistema" tabindex="-1">Estrutura do sistema <a class="header-anchor" href="#estrutura-do-sistema" aria-label="Permalink to &quot;Estrutura do sistema&quot;">​</a></h2><h3 id="t1" tabindex="-1">T1 <a class="header-anchor" href="#t1" aria-label="Permalink to &quot;T1&quot;">​</a></h3><ul><li>Filesystem.</li><li>Fonte material dos artefatos.</li></ul><h3 id="t2" tabindex="-1">T2 <a class="header-anchor" href="#t2" aria-label="Permalink to &quot;T2&quot;">​</a></h3><ul><li>PostgreSQL.</li><li>Âncora canônica de identidade, versionamento, blobs, abstractions, links e reflections.</li></ul><h3 id="t3" tabindex="-1">T3 <a class="header-anchor" href="#t3" aria-label="Permalink to &quot;T3&quot;">​</a></h3><ul><li>Qdrant.</li><li>Porta de entrada por proximidade vetorial.</li><li>Útil para localizar sementes e bairros locais no espaço semântico.</li></ul><h3 id="t4" tabindex="-1">T4 <a class="header-anchor" href="#t4" aria-label="Permalink to &quot;T4&quot;">​</a></h3><ul><li>Camada de navegação topológica.</li><li>No runtime atual, implementada pragmaticamente sobre <code>links</code> persistidos e expansão restrita no subgrafo ativo.</li><li>Na visão do projeto, é mais do que ranking relacional: é a direção para uma navegação semântica acima dos índices.</li></ul><h3 id="t5" tabindex="-1">T5 <a class="header-anchor" href="#t5" aria-label="Permalink to &quot;T5&quot;">​</a></h3><ul><li>Reflections.</li><li>Traço introspectivo e memória derivada.</li></ul><h3 id="t6" tabindex="-1">T6 <a class="header-anchor" href="#t6" aria-label="Permalink to &quot;T6&quot;">​</a></h3><ul><li>Tempo.</li><li>Versionamento e contexto cronológico.</li></ul><h2 id="leitura-correta-do-t4" tabindex="-1">Leitura correta do T4 <a class="header-anchor" href="#leitura-correta-do-t4" aria-label="Permalink to &quot;Leitura correta do T4&quot;">​</a></h2><ul><li>O <code>T4</code> atual não é a formulação final da arquitetura.</li><li>O <code>T4</code> atual é um estágio operacional viável.</li><li>O destino do projeto continua sendo uma navegação semântica supra-index: <ul><li>alimentada por T2 e T3,</li><li>não reduzida a k-NN puro,</li><li>e não reduzida a PageRank relacional puro.</li></ul></li></ul><h2 id="invariantes-praticos" tabindex="-1">Invariantes práticos <a class="header-anchor" href="#invariantes-praticos" aria-label="Permalink to &quot;Invariantes práticos&quot;">​</a></h2><ul><li>T1 é a origem reconstruível.</li><li>T2, T3 e T4 podem ser regenerados.</li><li>Mudança de embedding, topologia ou geometria pode exigir reingestão total.</li><li>Compatibilidade legada não é prioridade do refactor atual.</li></ul><h2 id="limites-deste-documento" tabindex="-1">Limites deste documento <a class="header-anchor" href="#limites-deste-documento" aria-label="Permalink to &quot;Limites deste documento&quot;">​</a></h2><ul><li>Contrato operacional atual: <a href="/var/home/bruno/NEXUS/docs/CANONICAL_RUNTIME.html">CANONICAL_RUNTIME.md</a></li><li>Objetivo de memória operacional: <a href="/var/home/bruno/NEXUS/docs/CANONICAL_MEMORY_MODEL.html">CANONICAL_MEMORY_MODEL.md</a></li><li>Reconciliação específica do T4: <a href="/var/home/bruno/NEXUS/docs/CANONICAL_T4.html">CANONICAL_T4.md</a></li></ul><h2 id="leituras-de-apoio" tabindex="-1">Leituras de apoio <a class="header-anchor" href="#leituras-de-apoio" aria-label="Permalink to &quot;Leituras de apoio&quot;">​</a></h2><ul><li><a href="/var/home/bruno/NEXUS/docs/adr/REFATORACAO_MEMORIA_OPERACIONAL.html">REFATORACAO_MEMORIA_OPERACIONAL.md</a></li><li><a href="/var/home/bruno/NEXUS/docs/adr/ADR_007_CAUSALIDADE_TOPOLOGICA.html">ADR_007_CAUSALIDADE_TOPOLOGICA.md</a></li><li><a href="/var/home/bruno/NEXUS/docs/adr/SPARSE_TOPOLOGY_T4.html">SPARSE_TOPOLOGY_T4.md</a></li><li><a href="/var/home/bruno/NEXUS/docs/adr/VISION_T3_T4.html">VISION_T3_T4.md</a></li></ul>',26)])])}const p=e(t,[["render",l]]);export{m as __pageData,p as default};
